// Source file: HelloCompile.java
public class HelloCompile {
    public static void main(String[] args) {
        String message = "Hello";
        int count = 3;
        for (int i = 0; i < count; i++) {
            System.out.println(message + " #" + i);
        }
    }
}

// PHASE 1: Lexical Analysis (Scanner/Tokenizer)
// Input: character stream
// Output: token stream
// Tokens: [public][class][HelloCompile][{][public][static][void]
//         [main][(][String][[][]][args][)][{]...

// PHASE 2: Parsing (Syntax Analysis)
// Input: token stream
// Output: Abstract Syntax Tree (AST)
// AST Root: ClassDecl(HelloCompile)
//   MethodDecl(main, public static, void)
//     VarDecl(String, message, "Hello")
//     VarDecl(int, count, 3)
//     ForStmt(init=VarDecl(i,0), cond=i<count, update=i++, body=...)

// PHASE 3: Semantic Analysis
// - Type checking: i < count (int < int) ✓
// - Symbol resolution: System.out resolves to PrintStream field
// - Scope checking: message visible inside for-loop ✓

// PHASE 4: Bytecode Generation
// Output: HelloCompile.class (bytecode instructions)

// Demonstrates Java version compatibility
// Compile with Java 21: javac --release 21 VersionDemo.java
// Try to run with Java 11 JVM: java VersionDemo
// Result: java.lang.UnsupportedClassVersionError:
//   VersionDemo has been compiled by a more recent version of the
//   Java Runtime (class file version 65.0), this version of the
//   Java Runtime only recognizes class file versions up to 55.0

public class VersionDemo {
    public static void main(String[] args) {
        // Check the class file version of this compiled class
        int classFileMajorVersion = getClassFileVersion(VersionDemo.class);
        System.out.println("Class file version: " + classFileMajorVersion);
        System.out.println("Java version: " + (classFileMajorVersion - 44));

        // Version table:
        // Java 8  -> class file 52.0
        // Java 11 -> class file 55.0
        // Java 17 -> class file 61.0
        // Java 21 -> class file 65.0
    }

    static int getClassFileVersion(Class<?> clazz) {
        try (var is = clazz.getResourceAsStream(
                "/" + clazz.getName().replace('.', '/') + ".class")) {
            if (is == null) return -1;
            byte[] bytes = is.readAllBytes();
            // Bytes 6-7 are the major version number
            return ((bytes[6] & 0xFF) << 8) | (bytes[7] & 0xFF);
        } catch (Exception e) { return -1; }
    }
}

