public class StringConcatDemo {
    public static void main(String[] args) {
        String name = "World";
        int count = 42;

        // Java 8 and earlier: javac compiles this to StringBuilder
        String result = "Hello " + name + ", count=" + count;
        // Compiled to:
        // new StringBuilder().append("Hello ").append(name)
        //   .append(", count=").append(count).toString()

        // Java 9+: uses invokedynamic + StringConcatFactory
        // Bytecode: invokedynamic #bootstrap -> StringConcatFactory.makeConcatWithConstants
        // This allows JVM to optimize the concat strategy at runtime
        // (could use byte array directly, avoiding StringBuilder overhead)

        System.out.println(result);

        // Demonstrating with javap:
        // Java 8:  new, dup, invokespecial StringBuilder.<init>, ...
        // Java 9+: invokedynamic #2, "Hello \u0001, count=\u0001"
        //          \u0001 is placeholder for runtime argument
        showConcatApproach();
    }

    static void showConcatApproach() {
        String javaVersion = System.getProperty("java.version");
        int major = Integer.parseInt(javaVersion.split("[.]")[0]);
        if (major >= 9) {
            System.out.println("Using invokedynamic StringConcatFactory (Java 9+)");
        } else {
            System.out.println("Using StringBuilder (Java 8)");
        }
    }
}

