public class Q2 {
    public static boolean isJavaClassFile(byte[] fileBytes) {
        if (fileBytes == null || fileBytes.length < 4) return false;
        return (fileBytes[0] & 0xFF) == 0xCA &&
               (fileBytes[1] & 0xFF) == 0xFE &&
               (fileBytes[2] & 0xFF) == 0xBA &&
               (fileBytes[3] & 0xFF) == 0xBE;
    }

    public static int getClassFileMajorVersion(byte[] fileBytes) {
        if (fileBytes == null || fileBytes.length < 8) return -1;
        return ((fileBytes[6] & 0xFF) << 8) | (fileBytes[7] & 0xFF);
    }

    public static void main(String[] args) {
        byte[] magic = {(byte)0xCA, (byte)0xFE, (byte)0xBA, (byte)0xBE, 0, 0, 0, 61};
        System.out.println(isJavaClassFile(magic));          // true
        System.out.println(getClassFileMajorVersion(magic)); // 61 (Java 17)
        System.out.println("Java version: " + (getClassFileMajorVersion(magic) - 44)); // 17

