import javax.tools.*;
import java.io.*;
import java.net.*;
import java.nio.file.*;
import java.lang.reflect.*;

public class Q3 {
    public static void compileAndRun(String className, String sourceCode) throws Exception {
        // Step 1: Write source to temp file
        Path tempDir = Files.createTempDirectory("dyncompile");
        Path sourceFile = tempDir.resolve(className + ".java");
        Files.writeString(sourceFile, sourceCode);

        // Step 2: Compile with javax.tools API
        JavaCompiler compiler = ToolProvider.getSystemJavaCompiler();
        if (compiler == null) throw new IllegalStateException("JDK required (not JRE)");

        int result = compiler.run(null, null, null, sourceFile.toString());
        if (result != 0) throw new RuntimeException("Compilation failed");

        // Step 3: Load compiled class
        URLClassLoader loader = new URLClassLoader(
            new URL[]{tempDir.toUri().toURL()},
            ClassLoader.getSystemClassLoader());
        Class<?> clazz = loader.loadClass(className);

        // Step 4: Invoke main method
        Method main = clazz.getMethod("main", String[].class);
        main.invoke(null, (Object) new String[0]);

        loader.close();
    }

    public static void main(String[] args) throws Exception {
        compileAndRun("HelloRuntime",
            "public class HelloRuntime { " +
            "  public static void main(String[] a) { " +
            "    System.out.println(\"Compiled and run at runtime!\"); }}");
    }
}

