import java.nio.file.*;

public class Q4 {
    public static int getConstantPoolCount(byte[] classBytes) {
        if (classBytes == null || classBytes.length < 10) return -1;
        // Bytes 8-9: constant pool count (big-endian, 2 bytes)
        return ((classBytes[8] & 0xFF) << 8) | (classBytes[9] & 0xFF);
        // Note: actual entries = count - 1 (index starts at 1)
    }

    public static void main(String[] args) throws Exception {
        byte[] bytes = Files.readAllBytes(Path.of("Q4.class"));
        int count = getConstantPoolCount(bytes);
        System.out.println("Constant pool count: " + count);
        System.out.println("Actual entries: " + (count - 1));
        // A simple class typically has 15-30 constant pool entries
        // Large classes can have 500+ entries
    }
}

