        System.out.println("@SourceOnly visible at runtime: " + (src != null));     // false

        // CLASS: in .class file but NOT loaded into JVM memory by default
        ClassOnly cls = m.getAnnotation(ClassOnly.class);
        System.out.println("@ClassOnly visible at runtime: "  + (cls != null));     // false

        // RUNTIME: loaded into JVM, accessible via reflection
        RuntimeVisible rt = m.getAnnotation(RuntimeVisible.class);
        System.out.println("@RuntimeVisible at runtime: "     + (rt != null));      // true

        System.out.println("All runtime annotations: " + m.getAnnotations().length); // 1
    }
}

