public class Q6 {
    static final boolean DEBUG = false; // compile-time constant

    public static void demonstrateDeadCode() {
        // if(DEBUG) with a compile-time constant false:
        // javac knows DEBUG=false at compile time
        // -> emits NO bytecode for the block
        // -> but it's NOT a compile error (JLS special case for debug patterns)
        if (DEBUG) {
            System.out.println("Debug mode — no bytecode emitted");
        }

        // if(true): else branch is dead code
        // javac emits code only for the then-branch
        if (true) {
            System.out.println("Always executed"); // has bytecode
        } else {
            System.out.println("Never executed"); // no bytecode emitted
        }

        // After this method: verify with javap -c that debug and never blocks are absent
        System.out.println("Dead code eliminated by compiler");
    }

    public static void main(String[] args) {
        demonstrateDeadCode();
        // Output:
        // Always executed
        // Dead code eliminated by compiler
        // ("Debug mode" and "Never executed" have no bytecode)
    }
}

