import java.util.*;

public class Q7 {
    enum TokenType { KEYWORD, IDENTIFIER, NUMBER, STRING, OPERATOR, PUNCTUATION }
    record Token(TokenType type, String value) {
        public String toString() { return type + "(" + value + ")"; }
    }

    static final Set<String> KEYWORDS = Set.of(
        "public","private","class","int","void","if","else","return","new","static"
    );

    public static List<Token> tokenize(String source) {
        List<Token> tokens = new ArrayList<>();
        int i = 0;
        while (i < source.length()) {
            char c = source.charAt(i);

            if (Character.isWhitespace(c)) { i++; continue; } // skip whitespace

            if (Character.isLetter(c) || c == '_') {
                // Keyword or identifier
                int start = i;
                while (i < source.length() && (Character.isLetterOrDigit(source.charAt(i)) || source.charAt(i) == '_')) i++;
                String word = source.substring(start, i);
                tokens.add(new Token(KEYWORDS.contains(word) ? TokenType.KEYWORD : TokenType.IDENTIFIER, word));

            } else if (Character.isDigit(c)) {
                // Number literal
                int start = i;
                while (i < source.length() && Character.isDigit(source.charAt(i))) i++;
                tokens.add(new Token(TokenType.NUMBER, source.substring(start, i)));

            } else if (c == '"') {
                // String literal
                int start = ++i;
                while (i < source.length() && source.charAt(i) != '"') i++;
                tokens.add(new Token(TokenType.STRING, source.substring(start, i++)));

            } else if ("+-*/=!<>".indexOf(c) >= 0) {
                // Operator (handle == and != as two-char)
                if (i + 1 < source.length() && source.charAt(i+1) == '=') {
                    tokens.add(new Token(TokenType.OPERATOR, "" + c + '=')); i += 2;
                } else {
                    tokens.add(new Token(TokenType.OPERATOR, String.valueOf(c))); i++;
                }

            } else if ("{};(),".indexOf(c) >= 0) {
                tokens.add(new Token(TokenType.PUNCTUATION, String.valueOf(c))); i++;

            } else { i++; } // skip unknown
        }
        return tokens;
    }

    public static void main(String[] args) {
        System.out.println(tokenize("int x = 42;"));
        System.out.println(tokenize("public class Hello { }"));
        System.out.println(tokenize("if (a == 42) return \"ok\";"));
    }
}

