public class Q8 {
    interface AstNode {
        int evaluate();
        String toSource();
    }

    record NumberNode(int value) implements AstNode {
        public int evaluate() { return value; }
        public String toSource() { return String.valueOf(value); }
    }

    record BinaryOpNode(AstNode left, char op, AstNode right) implements AstNode {
        public int evaluate() {
            return switch (op) {
                case '+' -> left.evaluate() + right.evaluate();
                case '-' -> left.evaluate() - right.evaluate();
                case '*' -> left.evaluate() * right.evaluate();
                case '/' -> left.evaluate() / right.evaluate();
                default  -> throw new IllegalArgumentException("Unknown op: " + op);
            };
        }
        public String toSource() {
            return "(" + left.toSource() + " " + op + " " + right.toSource() + ")";
        }
    }

    record UnaryNegNode(AstNode child) implements AstNode {
        public int evaluate() { return -child.evaluate(); }
        public String toSource() { return "(-" + child.toSource() + ")"; }
    }

    public static void main(String[] args) {
        // -(3 + 4) * 2
        AstNode ast = new BinaryOpNode(
            new UnaryNegNode(new BinaryOpNode(new NumberNode(3), '+', new NumberNode(4))),
            '*',
            new NumberNode(2)
        );
        System.out.println(ast.toSource());  // ((-(3 + 4)) * 2)
        System.out.println(ast.evaluate());  // -14

        // 10 - 3 * 2 = 4
        AstNode ast2 = new BinaryOpNode(
            new NumberNode(10), '-',
            new BinaryOpNode(new NumberNode(3), '*', new NumberNode(2)));
        System.out.println(ast2.evaluate()); // 4
    }
}

