import java.util.*;

public class Q9 {
    Map<String, Set<String>> reverseGraph = new HashMap<>();

    public void addDependency(String classA, String classB) {
        // A depends on B: add A to B's reverse-dependents
        reverseGraph.computeIfAbsent(classB, k -> new HashSet<>()).add(classA);
        reverseGraph.computeIfAbsent(classA, k -> new HashSet<>()); // ensure A exists
    }

    public Set<String> getAffectedByChange(String changedClass) {
        Set<String> affected = new HashSet<>();
        Queue<String> queue = new LinkedList<>();
        queue.add(changedClass);
        affected.add(changedClass);

        while (!queue.isEmpty()) {
            String current = queue.poll();
            for (String dependent : reverseGraph.getOrDefault(current, Set.of())) {
                if (!affected.contains(dependent)) {
                    affected.add(dependent);
                    queue.add(dependent); // BFS: propagate transitively
                }
            }
        }
        return affected;
    }

    public static void main(String[] args) {
        Q9 g = new Q9();
        g.addDependency("Controller", "Service");
        g.addDependency("Service",    "Repository");
        g.addDependency("Service",    "Model");
        g.addDependency("View",       "Model");

        System.out.println("Model changed, affects: " + g.getAffectedByChange("Model"));
        // {Model, Service, View, Controller}
        System.out.println("Repository changed: " + g.getAffectedByChange("Repository"));
        // {Repository, Service, Controller}
    }
}

