            String line = rawLine.trim();
            if (line.isEmpty()) { sb.append("\n"); continue; }

            // If line starts with '}' (or is just '}'), decrease indent first
            if (line.startsWith("}")) indent = Math.max(0, indent - 1);

            sb.append("    ".repeat(indent)).append(line).append("\n");

            // If line ends with '{', increase indent for next line
            if (line.endsWith("{")) indent++;
        }
        return sb.toString().trim();
    }

    public static void main(String[] args) {
        String ugly = "public class Foo {\nvoid bar() {\nif (true) {\nreturn;\n}\n}\n}";
