public class Q13 {
    sealed interface Expr permits Num, Add, Mul, Neg {}
    record Num(int v)                 implements Expr {}
    record Add(Expr left, Expr right) implements Expr {}
    record Mul(Expr left, Expr right) implements Expr {}
    record Neg(Expr expr)             implements Expr {}

    static int eval(Expr expr) {
        // Java 17+ pattern matching switch — compiler checks exhaustiveness
        return switch (expr) {
            case Num n  -> n.v();
            case Add a  -> eval(a.left()) + eval(a.right());
            case Mul m  -> eval(m.left()) * eval(m.right());
            case Neg n  -> -eval(n.expr());
            // No default needed — sealed interface is exhaustive
        };
    }

    public static void main(String[] args) {
        Expr e = new Add(new Num(3), new Mul(new Num(4), new Neg(new Num(2))));
        System.out.println(eval(e)); // -5

        // More complex: (2 + 3) * -(1 + 4) = 5 * -5 = -25
        Expr e2 = new Mul(
            new Add(new Num(2), new Num(3)),
            new Neg(new Add(new Num(1), new Num(4))));
        System.out.println(eval(e2)); // -25
    }
}

