public class Q15 {
    public static String desugarRecord(String recordName, String[][] fields) {
        StringBuilder sb = new StringBuilder();
        sb.append("public final class ").append(recordName).append(" {\n");

        // Final fields
        for (String[] f : fields)
            sb.append("    private final ").append(f[0]).append(" ").append(f[1]).append(";\n");
        sb.append("\n");

        // Canonical constructor
        sb.append("    public ").append(recordName).append("(");
        for (int i = 0; i < fields.length; i++) {
            if (i > 0) sb.append(", ");
            sb.append(fields[i][0]).append(" ").append(fields[i][1]);
        }
        sb.append(") {\n");
        for (String[] f : fields)
            sb.append("        this.").append(f[1]).append(" = ").append(f[1]).append(";\n");
        sb.append("    }\n\n");

        // Accessor methods (no 'get' prefix — Java record style)
        for (String[] f : fields)
            sb.append("    public ").append(f[0]).append(" ").append(f[1])
              .append("() { return ").append(f[1]).append("; }\n");
        sb.append("\n");

        // equals()
        sb.append("    @Override public boolean equals(Object o) {\n")
          .append("        if (this == o) return true;\n")
          .append("        if (!(o instanceof ").append(recordName).append(" r)) return false;\n");
        for (String[] f : fields)
            sb.append("        if (!java.util.Objects.equals(").append(f[1])
              .append(", r.").append(f[1]).append(")) return false;\n");
        sb.append("        return true;\n    }\n\n");

        // hashCode()
        sb.append("    @Override public int hashCode() {\n")
          .append("        return java.util.Objects.hash(");
        for (int i = 0; i < fields.length; i++) {
            if (i > 0) sb.append(", ");
            sb.append(fields[i][1]);
        }
        sb.append(");\n    }\n\n");

        // toString() — record format: Name[f1=v1, f2=v2]
        sb.append("    @Override public String toString() {\n")
          .append("        return \"").append(recordName).append("[" + "\" +\n");
        for (int i = 0; i < fields.length; i++) {
            if (i > 0) sb.append("            + \", \" +\n");
            sb.append("            \"").append(fields[i][1]).append("=\" + ").append(fields[i][1]).append(" +\n");
        }
        sb.append("            \"]\";\n    }\n}");
        return sb.toString();
    }

    public static void main(String[] args) {
        System.out.println(desugarRecord("Point", new String[][]{{"int","x"},{"int","y"}}));
    }
}

