public class Q17 {
    public static String minify(String source) {
        // Step 1: Remove block comments /* ... */ (including multiline)
        String s = source.replaceAll("/\\*[\\s\\S]*?\\*/", " ");

        // Step 2: Remove line comments // ...
        s = s.replaceAll("//[^\n]*", "");

        // Step 3: Replace multiple whitespace (spaces, tabs, newlines) with single space
        s = s.replaceAll("[\\s]+", " ");

        // Step 4: Trim and collapse spaces around common tokens
        s = s.replaceAll("\\s*([{};()=+\\-*/<>,])\\s*", "$1");

        return s.trim();
    }

    public static void main(String[] args) {
        String code = "// Header comment\n" +
            "public class Foo {\n" +
            "  /* field */\n" +
