import java.util.*;

public class Q18 {
    static String[] pos = new String[1];

    static String parseType(String d, int[] i) {
        if (i[0] >= d.length()) return "?";
        char c = d.charAt(i[0]++);
        return switch (c) {
            case 'Z' -> "boolean"; case 'B' -> "byte"; case 'C' -> "char";
            case 'S' -> "short";   case 'I' -> "int";  case 'J' -> "long";
            case 'F' -> "float";   case 'D' -> "double"; case 'V' -> "void";
            case '[' -> parseType(d, i) + "[]";
            case 'L' -> {
                int end = d.indexOf(';', i[0]);
                String cls = d.substring(i[0], end).replace('/', '.');
                i[0] = end + 1;
                // Use simple name
                yield cls.contains(".") ? cls.substring(cls.lastIndexOf('.') + 1) : cls;
            }
            default -> String.valueOf(c);
        };
    }

    public static String parseDescriptor(String descriptor) {
        int[] i = {1}; // skip '('
        List<String> params = new ArrayList<>();
        while (i[0] < descriptor.length() && descriptor.charAt(i[0]) != ')') {
            params.add(parseType(descriptor, i));
        }
        i[0]++; // skip ')'
        String ret = parseType(descriptor, i);
        return ret + " method(" + String.join(", ", params) + ")";
    }

    public static void main(String[] args) {
        System.out.println(parseDescriptor("(ILjava/lang/String;[D)Z"));
        System.out.println(parseDescriptor("(II)I"));
        System.out.println(parseDescriptor("()V"));
    }
}

