import java.util.*;

public class Q19 {
    enum TT { NUM, PLUS, MINUS, STAR, SLASH, LPAREN, RPAREN }
    record Tok(TT type, int value) {}

    static List<Tok> tokenize(String s) {
        List<Tok> toks = new ArrayList<>();
        for (int i = 0; i < s.length(); ) {
            char c = s.charAt(i);
            if (Character.isWhitespace(c)) { i++; continue; }
            if (Character.isDigit(c)) {
                int n = 0; while (i < s.length() && Character.isDigit(s.charAt(i))) n = n*10 + (s.charAt(i++)-'0');
                toks.add(new Tok(TT.NUM, n)); continue;
            }
            toks.add(switch (c) {
                case '+' -> new Tok(TT.PLUS,0); case '-' -> new Tok(TT.MINUS,0);
                case '*' -> new Tok(TT.STAR,0); case '/' -> new Tok(TT.SLASH,0);
                case '(' -> new Tok(TT.LPAREN,0); case ')' -> new Tok(TT.RPAREN,0);
                default  -> throw new RuntimeException("Unknown: " + c);
            }); i++;
        }
        return toks;
    }

    int[] pos = {0};
    List<Tok> toks;

    Tok peek() { return pos[0] < toks.size() ? toks.get(pos[0]) : new Tok(TT.NUM, 0); }
    Tok consume() { return toks.get(pos[0]++); }

    // expr → term (('+' | '-') term)*
    int parseExpr() {
        int val = parseTerm();
        while (peek().type() == TT.PLUS || peek().type() == TT.MINUS) {
            TT op = consume().type();
            int right = parseTerm();
            val = (op == TT.PLUS) ? val + right : val - right;
        }
        return val;
    }

    // term → factor (('*' | '/') factor)*
    int parseTerm() {
        int val = parseFactor();
        while (peek().type() == TT.STAR || peek().type() == TT.SLASH) {
            TT op = consume().type();
            int right = parseFactor();
            val = (op == TT.STAR) ? val * right : val / right;
        }
        return val;
    }

    // factor → NUMBER | '(' expr ')'
    int parseFactor() {
        Tok t = consume();
        if (t.type() == TT.NUM) return t.value();
        if (t.type() == TT.LPAREN) {
            int val = parseExpr();
            consume(); // ')'
            return val;
        }
        throw new RuntimeException("Expected number or '('");
    }

    public static int evaluate(String expr) {
        Q19 parser = new Q19();
        parser.toks = tokenize(expr);
        return parser.parseExpr();
    }

    public static void main(String[] args) {
        System.out.println(evaluate("3 + 4 * 2 - 1"));  // 10
        System.out.println(evaluate("(3 + 4) * 2"));     // 14
        System.out.println(evaluate("10 / 2 + 3"));      // 8
        System.out.println(evaluate("2 * (3 + 4 * 2)"));  // 22
    }
}

