    Tok peek() { return p[0] < toks.size() ? toks.get(p[0]) : new Tok(TT.SEMI,null,0); }
    Tok consume() { return toks.get(p[0]++); }

    int parseExpr() {
        int v = parseTerm();
        while (peek().type() == TT.PLUS || peek().type() == TT.MINUS) {
            TT op = consume().type(); int r = parseTerm();
            v = op == TT.PLUS ? v+r : v-r;
        } return v;
    }
    int parseTerm() {
        int v = parseFactor();
        while (peek().type() == TT.STAR || peek().type() == TT.SLASH) {
            TT op = consume().type(); int r = parseFactor();
            v = op == TT.STAR ? v*r : v/r;
        } return v;
    }
    int parseFactor() {
        Tok t = consume();
        if (t.type() == TT.NUM)   return t.ival();
        if (t.type() == TT.IDENT) return vars.getOrDefault(t.sval(), 0);
        if (t.type() == TT.LPAREN) { int v = parseExpr(); consume(); return v; }
        throw new RuntimeException("Unexpected: " + t);
    }

    void run() {
        while (p[0] < toks.size()) {
            Tok t = peek();
            if (t.type() == TT.INT) {
                consume(); // 'int'
                String name = consume().sval(); // var name
                consume(); // '='
                int val = parseExpr();
                consume(); // ';'
                vars.put(name, val);
            } else if (t.type() == TT.PRINT) {
                consume(); consume(); // 'print' '('
                int val = parseExpr();
                consume(); consume(); // ')' ';'
                System.out.println(val);
            } else { consume(); } // skip unknown
        }
    }

    public static void execute(String program) {
        Q20 compiler = new Q20();
        compiler.toks = tokenize(program);
        compiler.run();
    }

    public static void main(String[] args) {
        execute("int a = 5;\nint b = 3 + a;\nprint(a * b);");
        // b = 3 + 5 = 8; a * b = 5 * 8 = 40
        execute("int x = 10;\nint y = x * 2 + 1;\nprint(y);");
        // y = 21
    }
}
